solutions.javascript:
// Solution: Use the 'in' operator to check the type of the input numbers and then perform the operation accordingly.
function calculator(operation: string, operand1: any, operand2: any): string {
  if (operation === 'add') {
    if ('number' in operand1 && 'number' in operand2) {
      return Number(operand1) + Number(operand2);
    } else if ('string' in operand1 && 'string' in operand2) {
      return operand1 + operand2;
    } else {
      return 'Invalid input types';
    }
  } else if (operation === 'multiply') {
    if ('number' in operand1 && 'number' in operand2) {
      return Number(operand1) * Number(operand2);
    } else if ('string' in operand1 && 'string' in operand2) {
      return operand1 + operand2;
    } else {
      return 'Invalid input types';
    }
  } else {
    return 'Invalid operation';
  }
}
